mapper.select:
SELECT DISTINCT o.id, o.order_number, o.order_mode, s.name AS approval_status, o.address_id, o.address_snapshot, o.user_id, o.order_date, o.ship_date, o.due_date, o.merchandise_amount, o.shipping_fee, o.discount_amount, o.total_amount, o.payment_status, o.comment FROM orders o JOIN order_approval_status s ON o.order_approval_status_id = s.id JOIN order_products op ON op.order_id = o.id AND op.deleted_date IS NULL JOIN products p ON p.id = op.product_id WHERE p.user_id = #{sellerId} AND o.deleted_date IS NULL
AND o.order_date >= #{startDate}
ORDER BY o.order_date DESC

mapper.update:
UPDATE orders o
JOIN order_approval_status s ON s.name = #{approvalStatusName}
SET o.order_approval_status_id = s.id,
    o.modified_date = CURRENT_TIMESTAMP
WHERE o.id = #{orderId}
  AND o.deleted_date IS NULL
